  1	import * as React from 'react';
  2	import classNames from 'classnames';
  3	import { useTranslation } from 'react-i18next';
  4	import { CheckIcon } from '@patternfly/react-icons';
  5	import {
  6	  Alert,
  7	  Card,
  8	  CardBody,
  9	  CardTitle,
 10	  Divider,
 11	  Grid,
 12	  GridItem,
 13	  Label,
 14	} from '@patternfly/react-core';
 15	import { SummaryProps, getTotalPipelineRuns } from './utils';
 16	import { PipelineModel, RepositoryModel } from '../../models';
 17	import { ALL_NAMESPACES_KEY } from '../../consts';
 18	
 19	import './PipelineRunsTotalCard.scss';
 20	import { MetricsQueryPrefix, PipelineQuery } from '../pipelines-metrics/utils';
 21	import {
 22	  usePipelineMetricsForAllNamespacePoll,
 23	  usePipelineMetricsForNamespacePoll,
 24	} from '../pipelines-metrics/hooks';
 25	import { getXaxisValues } from './dateTime';
 26	import { LoadingInline } from '../Loading';
 27	
 28	interface PipelinesRunsDurationProps {
 29	  namespace: string;
 30	  timespan: number;
 31	  interval: number;
 32	  summaryData?: SummaryProps;
 33	  bordered?: boolean;
 34	}
 35	
 36	const PipelineRunsTotalCardK8s: React.FC<PipelinesRunsDurationProps> = ({
 37	  namespace,
 38	  timespan,
 39	  interval,
 40	  bordered,
 41	}) => {
 42	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 43	  const [pipelineRunsTotalError, setPipelineRunsTotalError] = React.useState<
 44	    string | null
 45	  >(null);
 46	  const [
 47	    totalPipelineRunsData,
 48	    totalPipelineRunsError,
 49	    loadingTotalPipelineRunsData,
 50	  ] =
 51	    namespace == ALL_NAMESPACES_KEY
 52	      ? usePipelineMetricsForAllNamespacePoll({
 53	          timespan,
 54	          delay: interval,
 55	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
 56	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_ALL_NAMESPACE,
 57	          timeout: 90000,
 58	        })
 59	      : usePipelineMetricsForNamespacePoll({
 60	          namespace,
 61	          timespan,
 62	          delay: interval,
 63	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
 64	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE,
 65	          timeout: 90000,
 66	        });
 67	  const [tickValues, type] = getXaxisValues(timespan);
 68	
 69	  const totalPipelineRuns = React.useMemo(() => {
 70	    if (totalPipelineRunsError) {
 71	      return '-';
 72	    }
 73	    return getTotalPipelineRuns(totalPipelineRunsData, tickValues, type);
 74	  }, [totalPipelineRunsData, tickValues, type, totalPipelineRunsError]);
 75	
 76	  React.useEffect(() => {
 77	    const hasNonAbortError =
 78	      totalPipelineRunsError && totalPipelineRunsError.name !== 'AbortError';
 79	    setPipelineRunsTotalError(
 80	      hasNonAbortError
 81	        ? totalPipelineRunsError?.message ?? t('Unable to load pipeline runs')
 82	        : null,
 83	    );
 84	  }, [totalPipelineRunsError]);
 85	
 86	  return (
 87	    <>
 88	      <Card
 89	        className={classNames('pipeline-overview__totals-card', {
 90	          'card-border': bordered,
 91	        })}
 92	      >
 93	        <CardTitle>
 94	          <span>{t('Total runs')}</span>
 95	        </CardTitle>
 96	        <Divider />
 97	        <CardBody>
 98	          {pipelineRunsTotalError ? (
 99	            <Alert
100	              variant="danger"
101	              isInline
102	              title={t('Unable to load total runs')}
103	              className="pf-v6-u-mb-md"
104	            />
105	          ) : (
106	            <>
107	              <Grid hasGutter className="pipeline-overview__totals-card__grid">
108	                <GridItem span={9}>
109	                  <span>
110	                    <Label
111	                      variant="outline"
112	                      className="pipeline-overview__totals-card__label"
113	                    >
114	                      {PipelineModel.abbr}
115	                    </Label>
116	                    {t('Runs in pipelines')}
117	                  </span>
118	                </GridItem>
119	                <GridItem
120	                  span={3}
121	                  className="pipeline-overview__totals-card__value"
122	                >
123	                  {loadingTotalPipelineRunsData ? <LoadingInline /> : '-'}
124	                </GridItem>
125	              </Grid>
126	              <Grid hasGutter className="pipeline-overview__totals-card__grid">
127	                <GridItem span={9}>
128	                  <span>
129	                    <Label
130	                      variant="outline"
131	                      className="pipeline-overview__totals-card__repo-label"
132	                    >
133	                      {RepositoryModel.abbr}
134	                    </Label>
135	                    {t('Runs in repositories')}
136	                  </span>
137	                </GridItem>
138	                <GridItem
139	                  span={3}
140	                  className="pipeline-overview__totals-card__value"
141	                >
142	                  {loadingTotalPipelineRunsData ? <LoadingInline /> : '-'}
143	                </GridItem>
144	              </Grid>
145	              <Grid hasGutter>
146	                <GridItem span={9}>
147	                  <span>
148	                    <CheckIcon className="pipeline-overview__totals-card__icon" />
149	                    {t('Total runs')}
150	                  </span>
151	                </GridItem>
152	                <GridItem
153	                  span={3}
154	                  className="pipeline-overview__totals-card__value"
155	                >
156	                  {loadingTotalPipelineRunsData ? (
157	                    <LoadingInline />
158	                  ) : (
159	                    totalPipelineRuns
160	                  )}
161	                </GridItem>
162	              </Grid>
163	            </>
164	          )}
165	        </CardBody>
166	      </Card>
167	    </>
168	  );
169	};
170	
171	export default PipelineRunsTotalCardK8s;

